use crate::template::day;

fn problem_1(input: &str) -> isize {
    input
        .chars()
        .map(|c| match c {
            '(' => 1,
            ')' => -1,
            _ => 0,
        })
        .sum()
}

#[allow(dead_code)]
const fn problem_1_const(input: &str) -> isize {
    let len = input.len();
    let mut sum = 0;
    let input = input.as_bytes();
    let mut i = 0;
    while i < len {
        match input[i] {
            b'(' => sum += 1,
            b')' => sum -= 1,
            _ => {}
        }
        i += 1;
    }
    sum
}

fn problem_2(input: &str) -> usize {
    input
        .chars()
        .map(|c| match c {
            '(' => 1_isize,
            ')' => -1,
            _ => 0,
        })
        .scan(0, |acc, x| {
            *acc += x;
            if (*acc).is_negative() {
                None
            } else {
                Some(*acc)
            }
        })
        .count()
        + 1
}

#[allow(dead_code)]
const fn problem_2_const(input: &str) -> usize {
    let input = input.as_bytes();
    let len = input.len();
    let mut result = 0;
    let mut total = 0;
    let mut i = 0;
    while i < len {
        match input[i] {
            b'(' => total += 1,
            b')' => total -= 1,
            _ => {}
        }
        result += 1;
        if total < 0 {
            break;
        }
        i += 1;
    }
    result
}

